noncompliant_example:
uint32_t calculate_track_prediction(uint32_t depth) {
    if (depth == 0U) {
        return 1U;
    }
    return depth * calculate_track_prediction(depth - 1U);
}

compliant_example:
uint32_t calculate_track_prediction(uint32_t depth) {
    uint32_t result = 1U;
    for (uint32_t i = 1U; i <= depth; ++i) {
        result *= i;
    }
    return result;
}
